<script setup lang="ts">
  import { Task } from '~~/models/task';

  const router = useRouter();
  const storeTask = await useStoreTask();

  let showHidden = $ref(false);
  let newTaskName = $ref('');

  async function save() {
    const task = Task.fromData({ title: newTaskName });
    await storeTask.taskSave(task);
    newTaskName = '';
    return task;
  }

  function discard() {
    newTaskName = '';
  }

  async function saveAndEdit() {
    const task = await save();
    router.push({ path: `/task/${task.id}` });
  }

  const tasks = $computed(() =>
    showHidden ? storeTask.tasks : storeTask.tasksAvailable,
  );

  const showEye = $computed(
    () => storeTask.tasks.length > storeTask.tasksAvailable.length,
  );
</script>

<template>
  <NuxtLayout
    :is-loading="!storeTask.isLoaded"
    name="common"
  >
    <template #default>
      <TransitionFade
        group
        class="px-2 pt-2 flex flex-col gap-2"
      >
        <div
          v-if="!tasks.length"
          class="uppercase p-2 flex items-center justify-center"
        >
          <span v-if="!storeTask.tasks.length">No tasks</span>
          <span v-else>No tasks available</span>
        </div>
        <TaskListItem
          v-for="task in tasks"
          :key="task.id"
          :task="task"
        />
      </TransitionFade>
    </template>
    <template #footer>
      <Button
        v-if="newTaskName"
        icon="fa6-solid:xmark"
        flat
        @click="discard"
      />
      <Toggle
        v-else-if="showEye"
        v-model="showHidden"
        :class="[showHidden && 'text-primary']"
        flat
      >
        <Icon name="fa6-solid:eye" />
      </Toggle>
      <Input
        key="task-new"
        v-model="newTaskName"
        class="flex-grow"
        placeholder="New task"
        flat
      />
      <template v-if="newTaskName">
        <Button
          flat
          icon="fluent:save-edit-24-filled"
          @click="saveAndEdit"
        />
        <Button
          flat
          icon="fluent:save-24-filled"
          @click="save"
        />
      </template>
    </template>
  </NuxtLayout>
</template>

<style lang="scss"></style>
